VALUES
  ('pukao-d0d1b9a2-moex-00034', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-114-519af93a', 'sub-pukao-d0d1b9a2-03', NULL, 'single_choice', '依會計法有關政府會計組織之規定，下列敘述何者正確？', '["政府會計之組織，分為總會計、單位會計、單位會計之分會計、附屬單位會計、附屬單位會計 之分會計等五種", "各單位會計所需編製之會計報告各表，應按機關別編造之", "各單位會計之特種序時帳簿及明細分類帳簿，為求簡便計，得酌量減少編造之", "各單位會計或附屬單位會計之備查簿，除主計機關認為應設置者外，各機關或基金主管長官及 主辦會計人員，亦得按其需要情形，自行設置之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "0f5cc8580d42", "answer_pdf_sha1": "37c33dbb9846", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "415", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00035', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-114-519af93a', 'sub-pukao-d0d1b9a2-03', NULL, 'single_choice', '會計年度之開始及終了，依下列何法所定？', '["預算法", "決算法", "會計法", "審計法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "0f5cc8580d42", "answer_pdf_sha1": "37c33dbb9846", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "415", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00036', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-114-519af93a', 'sub-pukao-d0d1b9a2-03', NULL, 'single_choice', '依預算法及決算法等相關規定，下列何者屬應提出行政院會議之事項？①中央政府總預算案暨附', '["中央政府總決算暨附屬單位決算及綜計表（營業 及非營業部分）", "中央政府總預算暨附屬單位預算半年結算報告及綜計表（營業與非營業部分）", "預算之執行，遇國家發生特殊事故而有裁減經費之必要時", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "0f5cc8580d42", "answer_pdf_sha1": "37c33dbb9846", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "415", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00037', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-114-519af93a', 'sub-pukao-d0d1b9a2-03', NULL, 'single_choice', '依會計法規定，下列何者係由中央主計機關另訂定辦法處理之事項？①記帳本位幣如有特殊情形', '["對外之收款收據不經主辦會計人員或其授權人簽名或蓋章之特殊情形者", "採用機器處 理會計資料或貯存體之錯誤，其更正辦法", "集中處理會計事務者，其原始憑證之整理及保管", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "0f5cc8580d42", "answer_pdf_sha1": "37c33dbb9846", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "415", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00038', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-114-519af93a', 'sub-pukao-d0d1b9a2-03', NULL, 'single_choice', '行政院環境保護署於112年8月22日改制為環境部，轄下國家環境研究院由原行政院環境保護 署之「環境檢驗所」及「環境保護人員訓練所」整併組織改設而成，未合併以前原兩機關112年 度單位決算之編造，下列敘述何者正確？', '["由國家環境研究院代為分別編造", "由國家環境研究院一併編造", "由環境部代為分別編造", "由環境部一併編造"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "0f5cc8580d42", "answer_pdf_sha1": "37c33dbb9846", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "415", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00039', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-114-519af93a', 'sub-pukao-d0d1b9a2-03', NULL, 'single_choice', '依決算法規定，有關監察院對審計部編造之審核報告所列應行處分事項之處理作為，包括下列何者？', '["應賠償之收支尚未執行者，移送國庫主管機關或附屬單位決算之主管機關執行之", "對於各機 關剔除、繳還之款項，移送該機關查明責任", "應懲處之事件，依法移送該機關懲處之", "未盡 職責或效能過低應予告誡者，通知其上級機關之長官"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "0f5cc8580d42", "answer_pdf_sha1": "37c33dbb9846", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "415", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00040', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-114-519af93a', 'sub-pukao-d0d1b9a2-03', NULL, 'single_choice', '依預算法及決算法規定，下列特種基金何者不綜計列入中央政府總決算附屬單位決算及綜計表 （非營業部分）內？', '["勞工保險局作業基金", "保險業務發展基金", "全民健康保險基金", "國民年金保險基金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "0f5cc8580d42", "answer_pdf_sha1": "37c33dbb9846", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "415", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00041', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-114-519af93a', 'sub-pukao-d0d1b9a2-03', NULL, 'single_choice', '下列何者非屬預算籌劃、編造、審議、執行等過程中，依預算法規定應核轉或通知審計機關者？', '["中央主計機關核定之各機關分配預算", "各機關已報請上級主管機關核定並經中央主計機關備案之第一預備金支用", "各機關轉入下年度之應付款及保留數準備", "中央財政主管機關實地調查管理國家經費或財產者之專案報告"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "0f5cc8580d42", "answer_pdf_sha1": "37c33dbb9846", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "415", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00042', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-114-519af93a', 'sub-pukao-d0d1b9a2-03', NULL, 'single_choice', '各機關執行年度預算過程中，下列何者與預算法規定未符？', '["各機關執行歲出分配預算遇經費有不足時，皆應報請行政院核定動支第一預備金", "各機關原列計畫費用因事實需要奉准修訂致原列經費不敷時，得經行政院核准動支第二預備金", "誤付透付之金額及依法墊付金額，在會計年度結束後繳還者，均視為結餘，轉帳加入下年度之收入", "繼續經費之按年分配額，在一會計年度結束後，未經使用部分，得轉入下年度支用之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "0f5cc8580d42", "answer_pdf_sha1": "37c33dbb9846", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "415", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00043', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-114-519af93a', 'sub-pukao-d0d1b9a2-03', NULL, 'single_choice', '預算法關於歲入、歲出追加、追減預算之規定，下列敘述何者錯誤？', '["各機關依有關法律應補列追加預算者，得請求提出追加歲出預算", "各機關法定歲入有特別短收之情勢，不能依預算法第 71 條規定辦理裁減時，應由中央財政主 管機關籌劃抵補，並由上級主管機關提出追加、追減預算調整之", "各機關依法律增設新機關時，得請求提出追加歲出預算", "各機關所辦事業因重大事故經費超過法定預算時，得請求提出追加歲出預算"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:01+00:00", "source_pdf_sha1": "0f5cc8580d42", "answer_pdf_sha1": "37c33dbb9846", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "415", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL)
